def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        penalty = 0.0
        adjustment = 1.0
        decay = 1.0
        boost = 1.0
        cache = {}
        for j in range(1, 21):
            if j in cache:
                base_val = cache[j]
            else:
                base_val = np.power(j, 2) + np.sin(j * ratio) * 5 - np.log1p(abs(ratio - j/20))
                cache[j] = base_val
            if cap % (j+1) == 0:
                multiplier = 1.07 + 0.005 * j
            else:
                multiplier = 0.93 - 0.003 * j
            if ratio < 0.05 * j:
                score += base_val * multiplier / (1 + np.exp(-ratio * j))
            else:
                score += (np.cosh(j * 0.1) + ratio**1.5) * multiplier / (j+3)
            if (cap * j + j*j) % 13 == 0:
                score *= 1.03
            elif (cap + j*j*j) % 11 == 0:
                score *= 0.97
            if j % 5 == 0:
                sum_diff = 0.0
                for k in range(1, 8):
                    diff = cap - item * (k**3 + j)
                    if diff > 0:
                        if diff % (k + j%4 + 1) == 0:
                            sum_diff += np.sqrt(diff) / (k + 2)
                        else:
                            sum_diff -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        sum_diff -= abs(diff)**1.7 / (k + 4)
                penalty += sum_diff * 0.6
            if ratio > 0.9 and j % 4 == 0:
                adjustment *= 1.12 + 0.015*j
            elif ratio < 0.1 and j % 3 == 1:
                adjustment *= 0.88 - 0.02*j
            if (cap + j) % 9 == 0 and j % 2 == 1:
                decay *= 0.95
            else:
                decay *= 1.02
            if j % 6 == 0:
                boost *= 1.01 + 0.005 * j
        score += penalty
        score *= adjustment * decay * boost
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap+1)) * 1.1
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap)+2) * (1 + 2*ratio) * 0.95
            else:
                priorities[i] = -score / (cap + 4) * np.exp(-ratio**2) * 1.05
        if ratio > 1.1:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        else:
            priorities[i] *= 1.04
        if i % 2 == 0:
            priorities[i] *= 0.99
        else:
            priorities[i] *= 1.01
    return priorities
